mapper.insert:
/* StandardDisplayCategoryConnectCommandRepository.insertConnectList */

    INSERT INTO PR_STD_CTG_DISP_INFO (
        DISP_CTG_NO,
        STD_CTG_NO,
        DISP_YN
        /* SYS_MOD_ID, SYS_MOD_DTM 등 시스템 공통 필드는 AOP/Interceptor에서 처리한다고 가정 */
    ) VALUES (
        #{item.dispCtgNo},
        #{item.stdCtgNo},
        #{item.dispYn}
    )

mapper.update:
/* StandardDisplayCategoryConnectCommandRepository.updateConnectList */

    UPDATE PR_STD_CTG_DISP_INFO
    SET DISP_YN = #{item.dispYn}
    WHERE DISP_CTG_NO = #{item.dispCtgNo}
      AND STD_CTG_NO = #{item.stdCtgNo}

mapper.delete:
/* StandardDisplayCategoryConnectCommandRepository.deleteConnectList */

    DELETE FROM PR_STD_CTG_DISP_INFO
    WHERE DISP_CTG_NO = #{item.dispCtgNo}
      AND STD_CTG_NO = #{item.stdCtgNo}
